Cf,eAAgB,CAChB,4BACF,CAEA,uCACE,UAAW,CACX,WAAY,CACZ,WAAY,CACZ,iBAAkB,CAClB,sBAAuB,CACvB,2BAA+B,CAC/B,cAAe,CACf,YAAa,CACb,kBAAmB,CACnB,sBAAuB,CACvB,cAAe,CACf,uCACF,CAEA,6CACE,iCAAqC,CACrC,2BACF,CAEA,sCACE,MAAO,CACP,iBAAkB,CAClB,eACF,CAEA,0CACE,UAAW,CACX,YAAa,CACb,eAAgB,CAChB,YAAa,CACb,uCAA2C,CAC3C,iBAAkB,CAClB,2BAA+B,CAC/B,4BAAgC,CAChC,cAAe,CACf,yCAA4C,CAC5C,eAAgB,CAChB,YAAa,CACb,4BAA6B,CAC7B,gBAAiB,CACjB,wBAAyB,CACzB,WACF,CAEA,gDACE,mCACF,CAEA,uDACE,4BACF,CAEA,wCACE,YAAa,CACb,kBAAmB,CACnB,QAAS,CACT,iBAAkB,CAClB,2CACF,CAEA,uCACE,WAAY,CACZ,iBAAkB,CAClB,gBAAiB,CACjB,iCAAqC,CACrC,2BAA+B,CAC/B,cAAe,CACf,cAAe,CACf,uCACF,CAEA,6CACE,iCAAqC,CACrC,2BACF,CAEA,sCACE,cAAe,CACf,4BACF","sourcesContent":["<template>\n  <div class=\"chat-area\">\n    <!-- 消息列表 -->\n    <div ref=\"messagesRef\" class=\"chat-area__messages\">\n      <div v-if=\"store.chatHistory.length === 0\" class=\"chat-area__empty\">\n        <i class=\"fa-solid fa-comments\" />\n        <p>描述你想要的控制面板布局</p>\n        <p class=\"chat-area__hint\">例如：「把所有 COT 相关条目放一组，文风相关放一组」</p>\n      </div>\n\n      <div\n        v-for=\"msg in store.chatHistory\"\n        :key=\"msg.id\"\n        class=\"chat-area__bubble\"\n        :class=\"{ 'chat-area__bubble--user': msg.role === 'user', 'chat-area__bubble--ai': msg.role === 'assistant' }\"\n      >\n        <div class=\"chat-area__bubble-role\">\n          <i :class=\"msg.role === 'user' ? 'fa-solid fa-user' : 'fa-solid fa-robot'\" />\n        </div>\n        <div class=\"chat-area__bubble-content\">{{ msg.content }}</div>\n      </div>\n\n      <!-- 流式输出气泡 -->\n      <div v-if=\"store.isLoading\" class=\"chat-area__bubble chat-area__bubble--ai\">\n        <div class=\"chat-area__bubble-role\">\n          <i class=\"fa-solid fa-robot\" />\n        </div>\n        <div class=\"chat-area__bubble-content chat-area__bubble-content--streaming\">\n          <template v-if=\"store.streamingText\">{{ store.streamingText }}</template>\n          <template v-else><i class=\"fa-solid fa-spinner fa-spin\" /> AI 正在生成...</template>\n        </div>\n      </div>\n    </div>\n\n    <!-- 快捷操作 -->\n    <div class=\"chat-area__shortcuts\">\n      <button class=\"chat-area__shortcut-btn\" title=\"从预设扫描\" @click=\"store.autoGenerateFromPreset()\">\n        <i class=\"fa-solid fa-magnifying-glass\" />\n        从预设扫描\n      </button>\n      <button\n        class=\"chat-area__shortcut-btn\"\n        :class=\"{ 'chat-area__shortcut-btn--active': store.settings.custom_system_prompt }\"\n        title=\"系统提示词\"\n        @click=\"openPromptDialog\"\n      >\n        <i class=\"fa-solid fa-scroll\" />\n      </button>\n      <button class=\"chat-area__shortcut-btn\" title=\"清空对话\" @click=\"store.clearChat()\">\n        <i class=\"fa-solid fa-trash-can\" />\n      </button>\n    </div>\n\n    <!-- 系统提示词弹窗 -->\n    <div v-if=\"promptDialogOpen\" class=\"prompt-dialog__backdrop\" @mousedown.self=\"promptDialogOpen = false\">\n      <div class=\"prompt-dialog\" @mousedown.stop>\n        <div class=\"prompt-dialog__header\">\n          <span class=\"prompt-dialog__title\">系统提示词</span>\n          <button class=\"prompt-dialog__close\" @click=\"promptDialogOpen = false\">\n            <i class=\"fa-solid fa-xmark\" />\n          </button>\n        </div>\n        <div class=\"prompt-dialog__body\">\n          <textarea\n            v-model=\"effectivePrompt\"\n            class=\"prompt-dialog__textarea\"\n          />\n        </div>\n        <div class=\"prompt-dialog__footer\">\n          <button class=\"prompt-dialog__reset\" @click=\"resetPrompt\">\n            <i class=\"fa-solid fa-rotate-left\" /> 恢复默认\n          </button>\n          <span class=\"prompt-dialog__hint\">编辑后自动保存，恢复默认将使用自动生成的提示词</span>\n        </div>\n      </div>\n    </div>\n\n    <!-- 输入区 -->\n    <div class=\"chat-area__input-row\">\n      <input\n        v-model=\"inputText\"\n        class=\"chat-area__input\"\n        placeholder=\"描述你想要的面板...\"\n        :disabled=\"store.isLoading\"\n        @keydown.enter.prevent=\"handleSend\"\n      />\n      <button\n        class=\"chat-area__send-btn\"\n        :disabled=\"!inputText.trim() || store.isLoading\"\n        @click=\"handleSend\"\n      >\n        <i class=\"fa-solid fa-paper-plane\" />\n      </button>\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport { useStore } from './store';\n\nconst store = useStore();\nconst inputText = ref('');\nconst promptDialogOpen = ref(false);\n\n// 可写计算属性：显示自定义或默认，只有用户实际编辑时才写入 custom_system_prompt\nconst effectivePrompt = computed({\n  get: () => {\n    if (store.settings.custom_system_prompt) {\n      return store.settings.custom_system_prompt;\n    }\n    store.scanPreset();\n    return store.getDefaultSystemPrompt();\n  },\n  set: (val: string) => {\n    store.settings.custom_system_prompt = val;\n  },\n});\n\nfunction openPromptDialog() {\n  promptDialogOpen.value = true;\n}\n\nfunction resetPrompt() {\n  store.settings.custom_system_prompt = '';\n}\nconst messagesRef = ref<HTMLElement>();\n\nasync function handleSend() {\n  const text = inputText.value.trim();\n  if (!text || store.isLoading) return;\n\n  inputText.value = '';\n  await store.sendChat(text);\n\n  // 滚动到底部\n  await nextTick();\n  if (messagesRef.value) {\n    messagesRef.value.scrollTop = messagesRef.value.scrollHeight;\n  }\n}\n\n// 自动滚动\nwatch(\n  () => store.chatHistory.length,\n  async () => {\n    await nextTick();\n    if (messagesRef.value) {\n      messagesRef.value.scrollTop = messagesRef.value.scrollHeight;\n    }\n  },\n);\n\n// 流式输出时也滚动到底部\nwatch(\n  () => store.streamingText,\n  async () => {\n    await nextTick();\n    if (messagesRef.value) {\n      messagesRef.value.scrollTop = messagesRef.value.scrollHeight;\n    }\n  },\n);\n</script>\n\n<style scoped>\n.chat-area {\n  display: flex;\n  flex-direction: column;\n  height: 100%;\n  min-width: 0;\n}\n\n.chat-area__messages {\n  flex: 1;\n  overflow-y: auto;\n  padding: 12px;\n  display: flex;\n  flex-direction: column;\n  gap: 8px;\n}\n\n.chat-area__empty {\n  display: flex;\n  flex-direction: column;\n  align-items: center;\n  justify-content: center;\n  height: 100%;\n  color: rgba(255, 255, 255, 0.3);\n  text-align: center;\n  gap: 4px;\n}\n\n.chat-area__empty i {\n  font-size: 28px;\n  margin-bottom: 8px;\n}\n\n.chat-area__empty p {\n  margin: 0;\n  font-size: 13px;\n}\n\n.chat-area__hint {\n  font-size: 11px !important;\n  color: rgba(255, 255, 255, 0.2) !important;\n}\n\n/* --- Bubbles --- */\n.chat-area__bubble {\n  display: flex;\n  gap: 8px;\n  max-width: 95%;\n}\n\n.chat-area__bubble--user {\n  align-self: flex-end;\n  flex-direction: row-reverse;\n}\n\n.chat-area__bubble--ai {\n  align-self: flex-start;\n}\n\n.chat-area__bubble-role {\n  width: 26px;\n  height: 26px;\n  border-radius: 50%;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 12px;\n  flex-shrink: 0;\n}\n\n.chat-area__bubble--user .chat-area__bubble-role {\n  background: rgba(100, 181, 246, 0.2);\n  color: #64b5f6;\n}\n\n.chat-area__bubble--ai .chat-area__bubble-role {\n  background: rgba(129, 199, 132, 0.2);\n  color: #81c784;\n}\n\n.chat-area__bubble-content {\n  padding: 8px 12px;\n  border-radius: 12px;\n  font-size: 12.5px;\n  line-height: 1.5;\n  white-space: pre-wrap;\n  word-break: break-word;\n}\n\n.chat-area__bubble--user .chat-area__bubble-content {\n  background: rgba(100, 181, 246, 0.12);\n  color: rgba(255, 255, 255, 0.9);\n  border-bottom-right-radius: 4px;\n}\n\n.chat-area__bubble--ai .chat-area__bubble-content {\n  background: rgba(255, 255, 255, 0.05);\n  color: rgba(255, 255, 255, 0.8);\n  border-bottom-left-radius: 4px;\n}\n\n.chat-area__loading {\n  display: flex;\n  align-items: center;\n  gap: 8px;\n  padding: 8px 12px;\n  color: rgba(255, 255, 255, 0.4);\n  font-size: 12px;\n}\n\n.chat-area__bubble-content--streaming {\n  max-height: 200px;\n  overflow-y: auto;\n  font-size: 11px;\n  opacity: 0.7;\n}\n\n/* --- Shortcuts --- */\n.chat-area__shortcuts {\n  display: flex;\n  gap: 4px;\n  padding: 4px 12px;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n}\n\n.chat-area__shortcut-btn {\n  display: flex;\n  align-items: center;\n  gap: 4px;\n  padding: 4px 8px;\n  border: none;\n  background: rgba(255, 255, 255, 0.06);\n  color: rgba(255, 255, 255, 0.55);\n  border-radius: 4px;\n  font-size: 11px;\n  cursor: pointer;\n  transition: background 0.15s, color 0.15s;\n}\n\n.chat-area__shortcut-btn:hover {\n  background: rgba(255, 255, 255, 0.1);\n  color: rgba(255, 255, 255, 0.8);\n}\n\n/* --- Input --- */\n.chat-area__input-row {\n  display: flex;\n  gap: 6px;\n  padding: 8px 12px;\n  border-top: 1px solid rgba(255, 255, 255, 0.06);\n}\n\n.chat-area__input {\n  flex: 1;\n  padding: 8px 12px;\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  border-radius: 8px;\n  background: rgba(255, 255, 255, 0.04);\n  color: rgba(255, 255, 255, 0.9);\n  font-size: 13px;\n  outline: none;\n  transition: border-color 0.2s;\n}\n\n.chat-area__input:focus {\n  border-color: rgba(100, 181, 246, 0.4);\n}\n\n.chat-area__input::placeholder {\n  color: rgba(255, 255, 255, 0.25);\n}\n\n.chat-area__send-btn {\n  width: 36px;\n  height: 36px;\n  border: none;\n  border-radius: 8px;\n  background: rgba(100, 181, 246, 0.2);\n  color: #64b5f6;\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  transition: background 0.15s, transform 0.1s;\n}\n\n.chat-area__send-btn:hover:not(:disabled) {\n  background: rgba(100, 181, 246, 0.35);\n  transform: scale(1.05);\n}\n\n.chat-area__send-btn:disabled {\n  opacity: 0.35;\n  cursor: not-allowed;\n}\n\n/* 系统提示词按钮高亮 */\n.chat-area__shortcut-btn--active {\n  color: #64b5f6 !important;\n  border-color: rgba(100, 181, 246, 0.25) !important;\n}\n\n/* 系统提示词弹窗 */\n.prompt-dialog__backdrop {\n  position: fixed;\n  inset: 0;\n  z-index: 100000;\n  background: rgba(0, 0, 0, 0.5);\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  animation: prompt-fade-in 0.15s ease-out;\n}\n\n@keyframes prompt-fade-in {\n  from { opacity: 0; }\n  to { opacity: 1; }\n}\n\n.prompt-dialog {\n  width: min(560px, 90vw);\n  max-height: 80vh;\n  display: flex;\n  flex-direction: column;\n  border-radius: 14px;\n  overflow: hidden;\n  background: rgba(22, 22, 30, 0.96);\n  backdrop-filter: blur(20px) saturate(180%);\n  -webkit-backdrop-filter: blur(20px) saturate(180%);\n  border: 1px solid rgba(255, 255, 255, 0.1);\n  box-shadow: 0 16px 48px rgba(0, 0, 0, 0.6);\n  animation: prompt-dialog-in 0.2s ease-out;\n}\n\n@keyframes prompt-dialog-in {\n  from { opacity: 0; transform: scale(0.94) translateY(12px); }\n  to { opacity: 1; transform: scale(1) translateY(0); }\n}\n\n.prompt-dialog__header {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  padding: 12px 16px;\n  border-bottom: 1px solid rgba(255, 255, 255, 0.06);\n}\n\n.prompt-dialog__title {\n  font-size: 14px;\n  font-weight: 600;\n  color: rgba(255, 255, 255, 0.85);\n}\n\n.prompt-dialog__close {\n  width: 28px;\n  height: 28px;\n  border: none;\n  border-radius: 6px;\n  background: transparent;\n  color: rgba(255, 255, 255, 0.4);\n  cursor: pointer;\n  display: flex;\n  align-items: center;\n  justify-content: center;\n  font-size: 13px;\n  transition: background 0.15s, color 0.15s;\n}\n\n.prompt-dialog__close:hover {\n  background: rgba(255, 255, 255, 0.08);\n  color: rgba(255, 255, 255, 0.8);\n}\n\n.prompt-dialog__body {\n  flex: 1;\n  padding: 12px 16px;\n  overflow: hidden;\n}\n\n.prompt-dialog__textarea {\n  width: 100%;\n  height: 320px;\n  resize: vertical;\n  padding: 10px;\n  border: 1px solid rgba(255, 255, 255, 0.08);\n  border-radius: 8px;\n  background: rgba(0, 0, 0, 0.25);\n  color: rgba(255, 255, 255, 0.85);\n  font-size: 12px;\n  font-family: 'Consolas', 'Monaco', monospace;\n  line-height: 1.6;\n  outline: none;\n  transition: border-color 0.2s;\n  user-select: text;\n  -webkit-user-select: text;\n  cursor: text;\n}\n\n.prompt-di